const data = $json;
const buttons = [];

// Always show Confirm
buttons.push({text: "Confirm Dispatch", callback_data: "confirm_dispatch||" + data.ticket_id + "||" + data.category + "||" + data.vendor_index});

// Show Next if more vendors available
if (data.vendor_index + 1 < data.total_vendors) {
  buttons.push({text: "Next >>", callback_data: "dispatch||" + data.ticket_id + "||" + data.category + "||" + (data.vendor_index + 1)});
}

// Always show "Show All" as fallback
buttons.push({text: "Show All", callback_data: "manual||" + data.ticket_id + "||" + data.category});

return {
  json: {
    method: 'POST',
    url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
    body: {
      chat_id: '6216258938',
      text: data.text,
      reply_markup: { inline_keyboard: [buttons] }
    }
  }
};

// Merge normalized message data with tenant data
let normalized = {};
try { normalized = $('Normalize Telegram').item.json; } catch(e) {
  try { normalized = $('Normalize Email').item.json; } catch(e2) {
    try { normalized = $('Normalize SMS').item.json; } catch(e3) {
      try { normalized = $('Normalize WhatsApp').item.json; } catch(e4) {
        normalized = {};
      }
    }
  }
}

const tenant = $('Lookup Tenant').item.json;

return [{
  json: {
    ...tenant,
    norm_chat_id: normalized.chat_id || tenant.telegram_id || '',
    norm_message: normalized.message || '',
    norm_channel: normalized.channel || '',
    norm_ext_id: normalized.external_message_id || '',
    norm_subject: normalized.subject || '',
    norm_sender_identifier: normalized.sender_identifier || '',
    norm_has_media: normalized.has_media || false,
    norm_media_type: normalized.media_type || '',
    norm_media_id: normalized.media_id || '',
    norm_media_url: normalized.media_url || '',
  }
}];

// Extract message from Meta WhatsApp webhook payload
const body = $input.first().json.body || $input.first().json;
if (body.entry?.[0]?.changes?.[0]?.value?.statuses) { return []; }
const value = body.entry?.[0]?.changes?.[0]?.value;
const message = value?.messages?.[0];
if (!message || !message.from) { return []; }
return [{
  json: {
    from: message.from,
    message_id: message.id || '',
    text: message.text?.body || message.image?.caption || message.video?.caption || '',
    type: message.type || 'text',
    has_image: !!message.image,
    has_video: !!message.video,
    has_audio: !!message.audio,
    has_document: !!message.document,
    image_id: message.image?.id || '',
    video_id: message.video?.id || '',
    audio_id: message.audio?.id || '',
    document_id: message.document?.id || '',
    contact_name: value?.contacts?.[0]?.profile?.name || '',
  }
}];

const raw = $input.first().json;
let from = '', body = '', messageSid = '', mediaUrl = '', numMedia = 0;
if (raw.body && typeof raw.body === 'object' && raw.body.From) {
  from = raw.body.From; body = raw.body.Body || ''; messageSid = raw.body.MessageSid || '';
  mediaUrl = raw.body.MediaUrl0 || ''; numMedia = parseInt(raw.body.NumMedia || '0');
} else if (raw.body && typeof raw.body === 'string') {
  const params = new URLSearchParams(raw.body);
  from = params.get('From') || ''; body = params.get('Body') || ''; messageSid = params.get('MessageSid') || '';
  mediaUrl = params.get('MediaUrl0') || ''; numMedia = parseInt(params.get('NumMedia') || '0');
} else {
  from = raw.From || raw.from || ''; body = raw.Body || '';
  messageSid = raw.MessageSid || ''; mediaUrl = raw.MediaUrl0 || ''; numMedia = parseInt(raw.NumMedia || '0');
}
if (!from && !body && numMedia === 0) { return []; }
return [{ json: { phone: from.replace(/^\+/, ''), message: body, message_sid: messageSid, channel: 'sms', media_url: mediaUrl, num_media: numMedia } }];

const chatId = String($('Telegram Trigger').item.json.callback_query.message.chat.id);
const resolved = $('Resolve Ticket').first()?.json;
const ticketId = resolved?.ticket_id || '';
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('vidéo') || false;

const msg = isFrench
  ? 'Super! Le billet ' + ticketId + ' a été marqué comme résolu. Merci!'
  : 'Great! Ticket ' + ticketId + ' has been marked as resolved. Thank you!';

// Send ack message
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
  body: { chat_id: chatId, text: msg },
  json: true
});

return [{ json: { chat_id: chatId, ticket_id: ticketId, ack_msg: msg } }];

const chatId = $('Telegram Trigger').item.json.callback_query.message.chat.id;
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('vidéo') || false;

const msg = isFrench
  ? 'Pas de souci! Quelqu\'un de notre équipe vous contactera bientôt.'
  : 'No worries! Someone from our team will follow up with you soon.';

const result = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
  body: { chat_id: chatId, text: msg },
  json: true
});
return [{ json: result }];

// AI-powered video matching using Claude Haiku
const videos = $('Search Repair Videos').all().map(v => v.json);

// Get tenant message from Build AI Payload (upstream node)
let message = '';
let channel = '';
let chat_id = '';
let phone = '';
let email = '';
let responseText = '';

try {
  const payload = $('Build AI Payload').item.json;
  message = (payload.message || '').trim();
  channel = payload.channel || '';
  chat_id = payload.chat_id || '';
  phone = payload.phone || '';
  email = payload.email || '';
} catch(e) {
  // Fallback: try to get from Merge Tenant + Message
  try {
    const merged = $('Merge Tenant + Message').item.json;
    message = (merged.norm_message || '').trim();
    channel = merged.norm_channel || '';
    chat_id = merged.norm_chat_id || '';
    phone = merged.phone || '';
    email = merged.email || '';
  } catch(e2) {}
}

try {
  responseText = $('Call AI Agent').item.json.response_text || '';
} catch(e) {}

if (!message || message.length < 5) return [{ json: { has_video: false } }];

const videoList = videos.map((v, i) => i + ': "' + v.title + '"').join('\n');

let bestVideo = null;
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': 'ANTHROPIC_API_KEY_SET_IN_N8N_ENV',
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 20,
      messages: [{
        role: 'user',
        content: 'The tenant sent this message: "' + message + '"\n\nAvailable repair videos:\n' + videoList + '\n\nRULES:\n- Reply with ONLY a number OR "none"\n- A video is relevant ONLY if the tenant\'s message describes the EXACT same problem the video solves\n- "toilet" issues only match toilet videos, "faucet" only faucet, etc.\n- If tenant says "thank you", "ok", "yes", or confirms something — reply "none"\n- When in doubt, reply "none"'
      }]
    },
    json: true,
    timeout: 10000
  });

  const aiAnswer = (response.content?.[0]?.text || '').trim().toLowerCase().split(/[\s\n]/)[0];
  if (aiAnswer !== 'none' && !isNaN(parseInt(aiAnswer))) {
    const idx = parseInt(aiAnswer);
    if (idx >= 0 && idx < videos.length) bestVideo = videos[idx];
  }
} catch(e) {
  // API timeout or error — skip video suggestion
  return [{ json: { has_video: false } }];
}

return [{
  json: {
    has_video: bestVideo !== null,
    video_url: bestVideo?.video_url || '',
    video_title: bestVideo?.title || '',
    channel: channel,
    chat_id: chat_id,
    phone: phone,
    email: email,
    response_text: responseText
  }
}];

// Send video as follow-up if matched
const input = $input.first().json;
if (!input.has_video || !input.video_url) return [{ json: { sent: false } }];

const channel = input.channel;
const chat_id = input.chat_id;
const phone = (input.phone || '').replace(/[^0-9]/g, '');
const isFrench = (input.response_text || '').includes('Bonjour') || (input.response_text || '').includes('merci');

const videoMsg = isFrench
  ? 'Cette vidéo pourrait vous aider :\n' + input.video_title + '\n' + input.video_url
  : 'This video might help:\n' + input.video_title + '\n' + input.video_url;

const ticketLookup = input.chat_id || '';

if (channel === 'telegram') {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
    body: { chat_id: chat_id, text: videoMsg },
    json: true
  });

  const questionText = isFrench 
    ? 'Est-ce que cette vidéo a aidé à résoudre votre problème?'
    : 'Did this video help resolve your issue?';

  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
    body: {
      chat_id: chat_id,
      text: questionText,
      reply_markup: JSON.stringify({
        inline_keyboard: [[
          { text: isFrench ? 'Oui ✅' : 'Yes ✅', callback_data: 'video_yes||' + ticketLookup },
          { text: isFrench ? 'Non ❌' : 'No ❌', callback_data: 'video_no||' + ticketLookup }
        ]]
      })
    },
    json: true
  });
} else if (channel === 'whatsapp') {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v21.0/1002910989571888/messages',
    headers: { 'Content-Type': 'application/json' },
    body: { messaging_product: 'whatsapp', to: phone, type: 'text', text: { body: videoMsg } },
    json: true
  });
}

// Log the video suggestion as a message
try {
  const { Pool } = require('pg');
  // Can't use require in n8n code nodes, use helpers instead
} catch(e) {}

return [{ json: { sent: true, channel: channel, video_title: input.video_title, chat_id: chat_id, video_url: input.video_url, videoMsg: videoMsg } }];

const chatId = $('Telegram Trigger').item.json.callback_query.message.chat.id;
const reopened = $('Reopen Ticket').first()?.json;
const ticketId = reopened?.ticket_id || '';
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('problème') || false;

const msg = isFrench
  ? 'Merci de nous avoir informé. Le billet ' + ticketId + ' a été réouvert et quelqu\'un vous contactera bientôt.'
  : 'Thank you for letting us know. Ticket ' + ticketId + ' has been reopened and someone will follow up with you shortly.';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
  body: { chat_id: String(chatId), text: msg },
  json: true
});

return [{ json: { chat_id: String(chatId), ticket_id: ticketId, ack_msg: msg } }];

// Send typing indicator + check if AI already responded recently (dedup)
const msg = $('Telegram Trigger').item.json.message;
if (!msg || !msg.chat) return [];

const chatId = String(msg.chat.id);

// Send typing indicator immediately
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendChatAction',
  body: { chat_id: chatId, action: 'typing' },
  json: true
});

return [{ json: { ...$('Telegram Trigger').item.json, typing_sent: true } }];

// Check tenant's open tickets and prompt accordingly
const merged = $('Merge Tenant + Message').item.json;
const channel = merged.norm_channel;
const chatId = merged.norm_chat_id;
const phone = merged.phone || '';
const email = merged.email || '';
const pendingId = $('Save Pending Media').item.json.id;

// Query open tickets for this tenant
const tickets = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://n8n.srv1285597.hstgr.cloud/webhook/ticket-ops',
  body: { action: 'query', query: "SELECT ticket_id, category, LEFT(summary, 40) as summary FROM maintenance_requests WHERE (phone = '" + phone.replace(/'/g, "''") + "' OR tenant_email = '" + email.replace(/'/g, "''") + "' OR telegram_id = '" + chatId + "') AND status NOT IN ('closed', 'resolved') ORDER BY created_at DESC LIMIT 5" },
  json: true
}).catch(() => []);

// Store pending_id for later lookup
const shortId = pendingId.slice(-12);

if (channel === 'telegram') {
  let messageText = '';

  if (tickets && tickets.length > 0) {
    // Has open tickets — show numbered list
    messageText = '📸 Photo received! Which ticket is this for?\n\n';
    tickets.forEach((t, i) => {
      const summary = t.summary || t.category || 'Unknown';
      messageText += (i + 1) + '. ' + t.ticket_id + ' — ' + summary + '\n';
    });
    messageText += (tickets.length + 1) + '. 🆕 New issue\n\nReply with the number.';

    // Store the ticket mapping in pending_media for lookup when tenant replies
    // We'll use the file_url field to store the JSON mapping
    const mapping = tickets.map((t, i) => ({ num: i + 1, ticket_id: t.ticket_id }));
    mapping.push({ num: tickets.length + 1, ticket_id: 'NEW' });

    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.srv1285597.hstgr.cloud/webhook/ticket-ops',
      body: { action: 'query', query: "UPDATE pending_media SET file_url = '" + JSON.stringify(mapping).replace(/'/g, "''") + "' WHERE id = '" + pendingId + "'" },
      json: true
    }).catch(() => {});

  } else {
    // No open tickets — show category buttons for new ticket
    messageText = '📸 Photo received! What is this about?';
  }

  if (tickets && tickets.length > 0) {
    // Send as text message (tenant replies with number)
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: { chat_id: chatId, text: messageText },
      json: true
    });
  } else {
    // Send category buttons (no open tickets)
    const categories = [
      { text: '🔧 Plumbing', data: 'mc||plumb||' + shortId },
      { text: '⚡ Electrical', data: 'mc||elec||' + shortId },
      { text: '🌡️ Heating/AC', data: 'mc||hvac||' + shortId },
      { text: '🚪 Maintenance', data: 'mc||maint||' + shortId },
      { text: '🐛 Pest Control', data: 'mc||pest||' + shortId },
      { text: '📋 Other', data: 'mc||other||' + shortId },
    ];

    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: {
        chat_id: chatId,
        text: messageText,
        reply_markup: JSON.stringify({
          inline_keyboard: [
            [{ text: categories[0].text, callback_data: categories[0].data }, { text: categories[1].text, callback_data: categories[1].data }],
            [{ text: categories[2].text, callback_data: categories[2].data }, { text: categories[3].text, callback_data: categories[3].data }],
            [{ text: categories[4].text, callback_data: categories[4].data }, { text: categories[5].text, callback_data: categories[5].data }]
          ]
        })
      },
      json: true
    });
  }
}

return [{ json: { sent: true, pending_id: pendingId, has_tickets: tickets && tickets.length > 0 } }];

// Map short category codes back to full names
const callbackData = $('Parse Callback').item.json;
const shortCode = callbackData.ticket_id; // parts[1] = short category code
const shortId = callbackData.category;    // parts[2] = last 12 chars of pending_id
const chatId = callbackData.chat_id;

const codeMap = {
  plumb: 'plumbing', elec: 'electrical', hvac: 'hvac',
  maint: 'general_maintenance', pest: 'pest_control', other: 'general_inquiry'
};

const category = codeMap[shortCode] || 'general_inquiry';

return [{
  json: {
    short_id: shortId,
    category: category,
    chat_id: chatId
  }
}];

const chatId = $('Parse Callback').item.json.chat_id;
const category = $json.category || 'unknown';
const isFrench = false; // TODO: detect language

const categoryLabels = {
  plumbing: 'Plumbing', electrical: 'Electrical', hvac: 'Heating/AC',
  general_maintenance: 'General Maintenance', pest_control: 'Pest Control',
  general_inquiry: 'Other'
};

const label = categoryLabels[category] || category;
const msg = 'Got it! Your photo has been logged under **' + label + '**. We\'ll include it with your ticket.';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
  body: { chat_id: chatId, text: msg, parse_mode: 'Markdown' },
  json: true
});

return [{ json: { sent: true } }];
